1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5G processing fee for an empty item list", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result).toEqual({ results: [{ premium: 5 }] });
12	    });
13	    it.todo("returns base premium plus fee for a single sword (100 + 5 = 105)");
14	    it.todo("returns base premium plus fee for a single amulet (60 + 5 = 65)");
15	    it.todo("returns base premium plus fee for a single staff (80 + 5 = 85)");
16	    it.todo("returns base premium plus fee for a single potion (40 + 5 = 45)");
17	    it.todo("sums base premiums for multiple items (sword + amulet = 160 + 5 = 165)");
18	  });
19	
20	  describe("Quote - component premiums", () => {
21	    it.todo("returns 25G per component (2 runes = 50 + 5 = 55)");
22	    it.todo("applies building block discount for exactly 3 alike components (3 runes = 60 + 5 = 65)");
23	    it.todo("does not apply block discount for 4 alike components (4 runes = 100 + 5 = 105)");
24	    it.todo("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75 + 5 = 80)");
25	    it.todo("applies separate blocks for 3 runes and 3 moonstones (120 + 5 = 125)");
26	    it.todo("charges 175G base for 7 runes (no block, 7 * 25 = 175 + 5 = 180)");
27	  });
28	
29	  describe("Quote - item-specific modifiers", () => {
30	    it.todo("adds 50% cursed surcharge to cursed item base premium");
31	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
32	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
33	    it.todo("does not apply high-enchantment surcharge for enchantment 4");
34	    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
35	  });
36	
37	  describe("Quote - policy-wide modifiers", () => {
38	    it.todo("applies 10% first-insurance surcharge on policy base premium");
39	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
40	    it.todo("applies 15% follow-up discount on second quote step");
41	    it.todo("does not apply loyalty discount for customer with < 2 years");
42	  });
43	
44	  describe("Quote - integration", () => {
45	    it.todo("newcomer with cursed sword: 165G (100 base + 50 curse + 10 first + 5 fee)");
46	    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
47	    it.todo("rounds premium up in MHPCO's favor");
48	  });
49	
50	  describe("Quote - errors", () => {
51	    it.todo("rejects unknown item type with non-zero exit");
52	  });
53	
54	  describe("Claim - standard reimbursement", () => {
55	    it.todo("reimburses damage minus 100G deductible for a regular item");
56	    it.todo("applies deductible per damaged item (sword 500 + amulet 300 = 600 payout)");
57	    it.todo("reimburses component damage minus deductible (rune damage 200 = 100 payout)");
58	  });
59	
60	  describe("Claim - enchantment and material clauses", () => {
61	    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
62	    it.todo("fully reimburses dragon material then applies deductible");
63	    it.todo("applies 50% when both dragon material and enchantment >= 8 (50% wins)");
64	    it.todo("dragon material with enchantment < 8: full reimbursement minus deductible");
65	  });
66	
67	  describe("Claim - cap", () => {
68	    it.todo("caps total payout at 2x insurance sum");
69	    it.todo("tracks remaining cap across successive claims");
70	    it.todo("cap exhaustion: second claim reduced to remaining cap");
71	  });
72	
73	  describe("Claim - errors", () => {
74	    it.todo("rejects claim for item not in policy");
75	    it.todo("rejects claim with more damages of a type than policy covers");
76	    it.todo("rejects claim with negative damage amount");
77	  });
78	
79	  describe("CLI integration", () => {
80	    it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
81	  });
82	});
83

1	export function processScenario(_scenario: unknown): unknown {
2	  return { results: [{ premium: 5 }] };
3	}
